package hotelroombookingsystem;
import java.io.ByteArrayOutputStream; import java.io.PrintStream; import java.nio.charset.StandardCharsets;
final class MainTest { private MainTest(){} static void run(){String[] commands={"help","demo","availability-demo","overlap-demo","cancellation-demo","occupancy-demo","validation-demo"};for(String c:commands)Assertions.assertEquals(0,execute(new String[]{c}).code,c);Result empty=execute(new String[0]);Assertions.assertEquals(0,empty.code,"default help");Assertions.assertContains(empty.out,"commands","help output");Result bad=execute(new String[]{"bad"});Assertions.assertNotEquals(0,bad.code,"bad nonzero");Assertions.assertContains(bad.err,"Unknown command","stderr");Assertions.assertContains(execute(new String[]{"demo"}).out,"375.00","money format");}
private static Result execute(String[] a){ByteArrayOutputStream o=new ByteArrayOutputStream(),e=new ByteArrayOutputStream();int c=Main.run(a,new PrintStream(o,true,StandardCharsets.UTF_8),new PrintStream(e,true,StandardCharsets.UTF_8));return new Result(c,o.toString(StandardCharsets.UTF_8),e.toString(StandardCharsets.UTF_8));}private static final class Result{final int code;final String out;final String err;Result(int c,String o,String e){code=c;out=o;err=e;}}}
